+
+/** A condition accepted by conditional option helpers. */
+export type OptionCondition = string | OptionDependency | OptionDependencies;
+
+function normalizeOptionCondition(
+  condition: OptionCondition,
+  required: boolean,
+): OptionDependency | OptionDependencies {
+  const dependsOn = typeof condition === "string"
+    ? { option: condition }
+    : condition;
+  return required && !("option" in dependsOn)
+    ? { ...dependsOn, required: true }
+    : required
+    ? { anyOf: [dependsOn], required: true }
+    : dependsOn;
+}
+
+/** Creates an option whose dependency must be satisfied when it is used. */
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  ...args: readonly [...readonly OptionName[], ValueParser<M, T>]
+): Parser<M, T, ValueParserResult<T> | undefined>;
+export function requiredWhen(
+  condition: OptionCondition,
+  ...args: readonly OptionName[]
+): Parser<"sync", boolean, ValueParserResult<boolean> | undefined>;
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  ...args: readonly (OptionName | ValueParser<M, T>)[]
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return option(...args as readonly OptionName[], {
+    dependsOn: normalizeOptionCondition(condition, true),
+  }) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>;
+}
+
+/** Creates an option that is visible only when its condition is satisfied. */
+export function optionalWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  ...args: readonly [...readonly OptionName[], ValueParser<M, T>]
+): Parser<M, T, ValueParserResult<T> | undefined>;
+export function optionalWhen(
+  condition: OptionCondition,
+  ...args: readonly OptionName[]
+): Parser<"sync", boolean, ValueParserResult<boolean> | undefined>;
+export function optionalWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  ...args: readonly (OptionName | ValueParser<M, T>)[]
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return option(...args as readonly OptionName[], {
+    dependsOn: normalizeOptionCondition(condition, false),
+  }) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>;
+}
+
+/** Alias for {@link optionalWhen}. */
+export const conditionalOption = optionalWhen;
