+function findConditionalOptionTerm(usage: Usage): Extract<UsageTerm, { type: "option" }> | undefined {
+  for (const term of usage) {
+    if (term.type === "option" && term.dependsOn != null) return term;
+    if ((term.type === "optional" || term.type === "multiple")) {
+      const found = findConditionalOptionTerm(term.terms);
+      if (found != null) return found;
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) {
+        const found = findConditionalOptionTerm(terms);
+        if (found != null) return found;
+      }
+    }
+  }
+  return undefined;
+}
+
+function valueFromOptionState(state: unknown): { readonly present: boolean; readonly value: unknown } {
+  if (Array.isArray(state) && state.length === 1) return valueFromOptionState(state[0]);
+  if (isDependencySourceState(state)) return valueFromOptionState(state.result);
+  if (state != null && typeof state === "object" && "success" in state) {
+    const result = state as { readonly success: boolean; readonly value?: unknown };
+    return result.success ? { present: true, value: result.value } : { present: false, value: undefined };
+  }
+  return { present: false, value: undefined };
+}
+
+function dependencyConditions(
+  dependsOn: OptionDependency | OptionDependencies,
+): { readonly allOf: readonly OptionDependency[]; readonly anyOf: readonly OptionDependency[]; readonly required: boolean } {
+  if ("option" in dependsOn) return { allOf: [dependsOn], anyOf: [], required: false };
+  return { allOf: dependsOn.allOf ?? [], anyOf: dependsOn.anyOf ?? [], required: dependsOn.required ?? false };
+}
+
+function dependencyStatus(
+  dependsOn: OptionDependency | OptionDependencies,
+  state: Record<string | symbol, unknown>,
+  parsers: readonly [string | symbol, Parser<Mode, unknown, unknown>][],
+): { readonly satisfied: boolean; readonly hasExplicitFalsyValue: boolean; readonly failed: OptionDependency | undefined } {
+  const byReference = (condition: OptionDependency) => {
+    const pair = parsers.find(([key, parser]) =>
+      key === condition.option || parser.usage.some(function includesName(term): boolean {
+        if (term.type === "option") return term.names.includes(condition.option as never);
+        if (term.type === "optional" || term.type === "multiple") return term.terms.some(includesName);
+        return term.type === "exclusive" && term.terms.some((terms) => terms.some(includesName));
+      })
+    );
+    if (pair == null) return { satisfied: false, explicitFalsy: false };
+    const optionState = valueFromOptionState(state[pair[0]]);
+    const satisfied = "value" in condition
+      ? optionState.present && optionState.value === condition.value
+      : optionState.present && Boolean(optionState.value);
+    return { satisfied, explicitFalsy: optionState.present && !optionState.value };
+  };
+  const conditions = dependencyConditions(dependsOn);
+  const all = conditions.allOf.map(byReference);
+  const any = conditions.anyOf.map(byReference);
+  const allSatisfied = all.every((item) => item.satisfied);
+  const anySatisfied = any.length === 0 || any.some((item) => item.satisfied);
+  const failed = [...conditions.allOf, ...conditions.anyOf].find((condition) => !byReference(condition).satisfied);
+  return {
+    satisfied: allSatisfied && anySatisfied,
+    hasExplicitFalsyValue: [...all, ...any].some((item) => item.explicitFalsy),
+    failed,
+  };
+}
