      : parser.initialState;

    const fieldSuggestions = parser.suggest({
      ...contextWithRegistry,
      state: fieldState,
    }, prefix);

    suggestions.push(...fieldSuggestions);
  }

  yield* deduplicateSuggestions(suggestions);
